from __future__ import annotations

import pandas as pd


BASE_NON_FEATURE_COLUMNS = frozenset({
    "cms_code_enc",
    "window_size",
    "window_start",
    "window_end",
    "source_table_t",
    "source_table_t_plus_h",
    "is_active_now",
    "is_churned_now",
    "gate_group",
})

# Drop stale metadata if old cached tables still contain it. These columns are
# not generated by the current pipeline and must never enter the model.
LEGACY_LABEL_META_COLUMNS = frozenset({
    "label_source",
    "label_weight",
})

CHURN_ELIGIBILITY_COLUMNS = frozenset({
    "is_churn_eligible",
    "churn_ineligible_reason",
    "churn_active_months_in_window",
    "churn_required_active_months",
    "churn_item_sum_for_eligibility",
    "churn_revenue_sum_for_eligibility",
    "churn_avg_revenue_per_item_for_eligibility",
})

LABEL_AUDIT_COLUMNS = frozenset({
    "label_rule_reason",
})

NON_FEATURE_COLUMNS = (
    BASE_NON_FEATURE_COLUMNS
    | LEGACY_LABEL_META_COLUMNS
    | CHURN_ELIGIBILITY_COLUMNS
    | LABEL_AUDIT_COLUMNS
)


def non_feature_columns(
    label_col: str | None = None,
    extra_drop: set[str] | list[str] | tuple[str, ...] | None = None,
) -> set[str]:
    cols = set(NON_FEATURE_COLUMNS)
    if label_col:
        cols.add(label_col)
    if extra_drop:
        cols.update(str(c) for c in extra_drop)
    return cols


def feature_columns(
    df: pd.DataFrame,
    *,
    label_col: str | None = None,
    extra_drop: set[str] | list[str] | tuple[str, ...] | None = None,
) -> list[str]:
    drop_cols = non_feature_columns(label_col=label_col, extra_drop=extra_drop)
    return [c for c in df.columns if c not in drop_cols and not str(c).startswith("y_churn_")]


def split_numeric_categorical_features(
    df: pd.DataFrame,
    *,
    label_col: str | None = None,
    extra_drop: set[str] | list[str] | tuple[str, ...] | None = None,
) -> tuple[list[str], list[str]]:
    num_cols: list[str] = []
    cat_cols: list[str] = []
    for col in feature_columns(df, label_col=label_col, extra_drop=extra_drop):
        dtype = df[col].dtype
        if pd.api.types.is_datetime64_any_dtype(dtype):
            continue
        if pd.api.types.is_numeric_dtype(dtype):
            num_cols.append(col)
        else:
            cat_cols.append(col)
    return num_cols, cat_cols
